.plainlist--only-child > ol,
.plainlist--only-child > ul {
	line-height: inherit;
	list-style: none none;
	margin: 0;
	padding-left: 0;
}

.plainlist--only-child > ol li,
.plainlist--only-child > ul li {
	margin-bottom: 0;
}
